1	// claim-office.ts
2	//
3	// Design choices for the input shape (documented for future tests):
4	// - quote(input) takes an object with `customer` and `items`.
5	//   - customer: { yearsWithMHPCO: number, isFollowUpContract: boolean }
6	//     - yearsWithMHPCO: how long the customer has been with MHPCO (drives loyalty discount).
7	//     - isFollowUpContract: whether this quote is the customer's second/follow-up
8	//       contract in the scenario (drives the 15% follow-up discount).
9	//   - items: an array of items to be insured. Empty array means no items.
10	// - quote returns the premium in G as a number.
11	// - claim is also exported (per the spec import) but not yet implemented.
12	
13	export type Customer = {
14	  yearsWithMHPCO: number;
15	  isFollowUpContract: boolean;
16	};
17	
18	export type Item = {
19	  type: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
20	  cursed?: boolean;
21	  enchantment?: number;
22	  material?: string;
23	};
24	
25	export type QuoteInput = {
26	  customer: Customer;
27	  items: Item[];
28	};
29	
30	// Flat fee added to every quote at the very end (spec: "processing fee of 5 G").
31	// Currently observed in the empty-list test (premium = fee only).
32	const PROCESSING_FEE = 5;
33	
34	// Block-of-3 discount: when items are exactly 3 of the same type,
35	// the policy base premium for that group is a flat 60 G.
36	const BLOCK_SIZE = 3;
37	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
38	
39	// Base premium per item type, in G (before any modifiers or fees).
40	// Keyed by Item["type"] so adding a new item variant is caught at compile time
41	// (the Record will require a corresponding entry).
42	const BASE_PREMIUM_BY_TYPE: Record<Item["type"], number> = {
43	  sword: 100,
44	  amulet: 60,
45	  staff: 80,
46	  potion: 40,
47	  rune: 25,
48	  moonstone: 25,
49	};
50	
51	// Modifier rates expressed as numerator/denominator to avoid floating-point error
52	// for the integer-and-half cases under test (e.g. 100 * 1.1 ≠ 110 in IEEE-754).
53	//
54	// Item-level surcharges (applied to a single item's base premium):
55	const CURSED_SURCHARGE_NUM = 1;
56	const CURSED_SURCHARGE_DEN = 2; // +50%
57	const HIGH_ENCHANTMENT_SURCHARGE_NUM = 3;
58	const HIGH_ENCHANTMENT_SURCHARGE_DEN = 10; // +30%
59	const HIGH_ENCHANTMENT_THRESHOLD = 5;
60	//
61	// Policy-level modifiers (applied to the policy base premium):
62	const FIRST_INSURANCE_NUM = 1;
63	const FIRST_INSURANCE_DEN = 10; // +10%
64	const LOYALTY_DISCOUNT_NUM = 1;
65	const LOYALTY_DISCOUNT_DEN = 5; // -20%
66	const LOYALTY_THRESHOLD_YEARS = 2;
67	const FOLLOW_UP_DISCOUNT_NUM = 15;
68	const FOLLOW_UP_DISCOUNT_DEN = 100; // -15%
69	
70	// Component types eligible for the block-of-3 discount.
71	const COMPONENT_TYPES: ReadonlySet<Item["type"]> = new Set(["rune", "moonstone"]);
72	
73	function isComponent(item: Item): boolean {
74	  return COMPONENT_TYPES.has(item.type);
75	}
76	
77	function itemBaseOnly(item: Item): number {
78	  return BASE_PREMIUM_BY_TYPE[item.type];
79	}
80	
81	function itemSurcharges(item: Item): number {
82	  const base = BASE_PREMIUM_BY_TYPE[item.type];
83	  let surcharge = 0;
84	  if (item.cursed) {
85	    surcharge += (base * CURSED_SURCHARGE_NUM) / CURSED_SURCHARGE_DEN;
86	  }
87	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
88	    surcharge += (base * HIGH_ENCHANTMENT_SURCHARGE_NUM) / HIGH_ENCHANTMENT_SURCHARGE_DEN;
89	  }
90	  return surcharge;
91	}
92	
93	function groupBaseSum(items: Item[]): number {
94	  return items.reduce((sum, item) => sum + itemBaseOnly(item), 0);
95	}
96	
97	function groupByType(items: Item[]): Map<Item["type"], Item[]> {
98	  const groups = new Map<Item["type"], Item[]>();
99	  for (const item of items) {
100	    const group = groups.get(item.type) ?? [];
101	    group.push(item);
102	    groups.set(item.type, group);
103	  }
104	  return groups;
105	}
106	
107	function groupBasePremium(group: Item[]): number {
108	  if (group.length === BLOCK_SIZE && isComponent(group[0])) {
109	    return BLOCK_OF_THREE_BASE_PREMIUM;
110	  }
111	  return groupBaseSum(group);
112	}
113	
114	function policyBasePremium(items: Item[]): number {
115	  const groups = groupByType(items);
116	  return Array.from(groups.values()).reduce(
117	    (total, group) => total + groupBasePremium(group),
118	    0,
119	  );
120	}
121	
122	function totalItemSurcharges(items: Item[]): number {
123	  return items.reduce((sum, item) => sum + itemSurcharges(item), 0);
124	}
125	
126	// Apply a fraction (num/den) of `amount` only when `condition` holds.
127	// Used for policy-level modifiers that are either active or zero,
128	// keeping the integer-fraction precision used throughout the module.
129	function fractionWhen(amount: number, num: number, den: number, condition: boolean): number {
130	  return condition ? (amount * num) / den : 0;
131	}
132	
133	// Reject items whose `type` isn't in the known premium table.
134	// Throws before any pricing work so callers see a clear domain error
135	// rather than a downstream NaN from a missing base premium.
136	function validateItemTypes(items: Item[]): void {
137	  for (const item of items) {
138	    if (!(item.type in BASE_PREMIUM_BY_TYPE)) {
139	      throw new Error(`Unknown item type: '${item.type}'`);
140	    }
141	  }
142	}
143	
144	export function quote(input: QuoteInput): number {
145	  const { customer, items } = input;
146	  validateItemTypes(items);
147	  const policyBase = policyBasePremium(items);
148	  const surcharges = totalItemSurcharges(items);
149	  const firstInsurance = fractionWhen(policyBase, FIRST_INSURANCE_NUM, FIRST_INSURANCE_DEN, true);
150	  const loyalty = fractionWhen(
151	    policyBase,
152	    LOYALTY_DISCOUNT_NUM,
153	    LOYALTY_DISCOUNT_DEN,
154	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
155	  );
156	  const followUp = fractionWhen(
157	    policyBase,
158	    FOLLOW_UP_DISCOUNT_NUM,
159	    FOLLOW_UP_DISCOUNT_DEN,
160	    customer.isFollowUpContract,
161	  );
162	  return Math.ceil(policyBase + surcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE);
163	}
164	
165	// Insurance sum per item type, in G. Independent of BASE_PREMIUM_BY_TYPE
166	// even though current values happen to be 10× the base premium — these are
167	// distinct domain concepts (pricing vs coverage), and the block-of-3 spec
168	// test confirms premium discounts must not affect insurance sum.
169	const INSURANCE_SUM_BY_TYPE: Record<Item["type"], number> = {
170	  sword: 1000,
171	  amulet: 600,
172	  staff: 800,
173	  potion: 400,
174	  rune: 250,
175	  moonstone: 250,
176	};
177	
178	// Per-damage deductible: customer covers the first 100 G of each damage entry.
179	const DEDUCTIBLE_PER_DAMAGE = 100;
180	// Policy cap is 2× the total insurance sum.
181	const CAP_MULTIPLIER = 2;
182	
183	export type ClaimItem = {
184	  type: Item["type"];
185	  material?: string;
186	  enchantment?: number;
187	  cursed?: boolean;
188	};
189	
190	export type Damage = {
191	  itemType: Item["type"];
192	  amount: number;
193	};
194	
195	export type ClaimInput = {
196	  policy: { items: ClaimItem[]; remainingCap?: number };
197	  incident: { damages: Damage[] };
198	};
199	
200	export type ClaimResult = {
201	  payout: number;
202	  remainingCap: number;
203	};
204	
205	function policyInsuranceSum(items: ClaimItem[]): number {
206	  return items.reduce((sum, item) => sum + INSURANCE_SUM_BY_TYPE[item.type], 0);
207	}
208	
209	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
210	
211	function isHighEnchantmentClaim(item: ClaimItem | undefined): boolean {
212	  return item?.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
213	}
214	
215	function damagePayout(damage: Damage, items: ClaimItem[]): number {
216	  const item = items.find((i) => i.type === damage.itemType);
217	  const reimbursable = isHighEnchantmentClaim(item) ? damage.amount / 2 : damage.amount;
218	  return Math.max(0, reimbursable - DEDUCTIBLE_PER_DAMAGE);
219	}
220	
221	function totalPayout(damages: Damage[], items: ClaimItem[]): number {
222	  return damages.reduce((total, damage) => total + damagePayout(damage, items), 0);
223	}
224	
225	function countOccurrences(types: Item["type"][]): Map<Item["type"], number> {
226	  const counts = new Map<Item["type"], number>();
227	  for (const type of types) {
228	    counts.set(type, (counts.get(type) ?? 0) + 1);
229	  }
230	  return counts;
231	}
232	
233	export function claim(input: ClaimInput): ClaimResult {
234	  const { items, remainingCap } = input.policy;
235	  const { damages } = input.incident;
236	  for (const damage of damages) {
237	    if (damage.amount < 0) {
238	      throw new Error(`Damage amount cannot be negative: ${damage.amount}`);
239	    }
240	  }
241	  const policyCounts = countOccurrences(items.map((i) => i.type));
242	  const damageCounts = countOccurrences(damages.map((d) => d.itemType));
243	  for (const [type, count] of damageCounts) {
244	    const covered = policyCounts.get(type) ?? 0;
245	    if (count > covered) {
246	      throw new Error(
247	        `Claim has ${count} damage entries of type '${type}' but policy covers only ${covered}`,
248	      );
249	    }
250	  }
251	  const cap = remainingCap ?? CAP_MULTIPLIER * policyInsuranceSum(items);
252	  const payout = Math.floor(Math.min(totalPayout(damages, items), cap));
253	  return { payout, remainingCap: cap - payout };
254	}
