5	describe("MHPCO quote - base premiums and processing fee", () => {
6	  it("quote with empty item list returns premium of 5 G (only the processing fee)", () => {
7	    const result = quote({
8	      customer: { yearsWithMHPCO: 0, isFollowUpContract: false },
9	      items: [],
10	    });
11	    expect(result).toBe(5);
12	  });
13	  it("quote for a plain sword (no modifiers, no customer history) returns 115 G (100 base + 10 first insurance + 5 fee)", () => {
14	    const result = quote({
15	      customer: { yearsWithMHPCO: 0, isFollowUpContract: false },
16	      items: [{ type: "sword" }],
17	    });
18	    expect(result).toBe(115);
19	  });
20	  it("quote for a plain amulet returns 71 G (60 + 6 first insurance + 5 fee)", () => {
21	    const result = quote({
22	      customer: { yearsWithMHPCO: 0, isFollowUpContract: false },
23	      items: [{ type: "amulet" }],
24	    });
25	    expect(result).toBe(71);
26	  });
27	  it("quote for a plain staff returns 93 G (80 + 8 first insurance + 5 fee)", () => {
28	    const result = quote({
29	      customer: { yearsWithMHPCO: 0, isFollowUpContract: false },
30	      items: [{ type: "staff" }],
31	    });
32	    expect(result).toBe(93);
33	  });
34	  it("quote for a plain potion returns 49 G (40 + 4 first insurance + 5 fee)", () => {
35	    const result = quote({
36	      customer: { yearsWithMHPCO: 0, isFollowUpContract: false },
37	      items: [{ type: "potion" }],
38	    });
39	    expect(result).toBe(49);
40	  });
41	  it("quote for a single rune returns 33 G (25 + 2.5 first insurance + 5 fee, rounded up)", () => {
42	    const result = quote({
43	      customer: { yearsWithMHPCO: 0, isFollowUpContract: false },
44	      items: [{ type: "rune" }],
45	    });
46	    expect(result).toBe(33);
47	  });
48	});
