148	describe("MHPCO quote - policy-wide modifiers and processing fee", () => {
149	  it("customer with exactly 2 years receives 20% loyalty discount on policy base premium", () => {
150	    const result = quote({
151	      customer: { yearsWithMHPCO: 2, isFollowUpContract: false },
152	      items: [{ type: "sword" }],
